$(document).ready(function(){$(document).on("click",".reviews-share .share_link",function(){var e=$(".reviews-share").find(".share_link").html(),i=$(this).data("url");$("body").append('<div class="reviews-sharelink-popup" id="reviews-sharelink-popup"><p class="modal-title">'+e+'</p><span id="modal_close"></span><div class="reviews-sharelink-input-container"><input class="text reviews-sharelink-text" value="'+i+'"><button class="copy-in-buffer"><svg class="icon_copy_link" width="16" height="16">\n<use xlink:href="/local/templates/sotbit_origami/assets/img/sprite.svg#icon_copy_link"></use>\n</svg></button></div></div><div  id="reviews-sharelink-overlay"></div>'),document.querySelector(".copy-in-buffer")&&document.querySelector(".copy-in-buffer").addEventListener("click",function(){document.querySelector(".reviews-sharelink-text").select(),document.execCommand("copy")}),$("#reviews-sharelink-overlay").fadeIn(400,function(){var e=document.documentElement,i=$("#reviews-sharelink-popup").outerWidth(!0),s=parseInt($("#reviews-sharelink-popup").outerHeight(!0)),n=e.clientWidth/2-i/2,t=e.clientHeight/2-s/2;$("#reviews-sharelink-popup").css("display","block").animate({opacity:1,top:t,left:n},200)})}),$(document).on("click","#reviews-sharelink-popup #modal_close, #reviews-sharelink-overlay",function(){$("#reviews-sharelink-popup").animate({opacity:0,top:"45%"},200,function(){$(this).css("display","none"),$("#reviews-sharelink-overlay").fadeOut(400,function(){$("#reviews-sharelink-overlay").remove(),$("#reviews-sharelink-popup").remove()})})})});